def findSmallestRegion(regions, region1, region2):
    parents = {}
    for r in regions:
        for i in range(1, len(r)):
            parents[r[i]] = r[0]
    ancestors = set()
    while region1:
        ancestors.add(region1)
        region1 = parents.get(region1)
    while region2 not in ancestors:
        region2 = parents.get(region2)
    return region2

